/* wif-das-robotpackcomplete-sql-oracle.xml - insertRobDasIntegrationResultWave - RobotDAS 포장완료 Result 웨이브 INSERT SQL */
INSERT INTO TWIF_ROBDAS_PAKCOMPL_WA
(
	WASEQ
	,CTKEY
	,OWKEY
	,WAHDKEY
	,WAHDDAY
	,IFCD
	,WIFIFID
	,IFID
	,IFREQDT
	,IFTYPE
	,IFSRCMODULE
	,IFTGTMODULE
	,IFSTATUS
	,IFERRCD
	,IFERRMSG
	,IFPRCSDATE
	,ORD
	,INSERTDATE
	,INSERTURKEY
	,UPDATEDATE
	,UPDATEURKEY
	,IFRETRYYN
	,IFRETRYIFID
)
VALUES
(
	#{waSeq}
	,#{ctKey}
	,#{owKey}
	,#{waHdKey}
	,#{waHdDay}
	,#{ifCd}
	,#{wifIfId}
	,#{ifId}
	,#{ifReqDt}
	,#{ifType}
	,#{ifSrcModule}
	,#{ifTgtModule}
	,#{ifStatus}
	,#{ifErrCd}
	,#{ifErrMsg}
	,#{ifPrcsDate}
	,#{ord}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
	,#{ifretryyn}
	,#{ifretryifid}
)

